// Strip the data URL prefix and extract base64 + media type
const item = $input.first();
const imageDataUrl = item.json.image || '';
const filename     = item.json.filename        || 'photo.jpg';
const matchCount   = item.json.match_count     || 6;
const matchThreshold = item.json.match_threshold || 0.30;

let base64Data = imageDataUrl;
let mediaType  = 'image/jpeg';

if (imageDataUrl.startsWith('data:')) {
  const comma = imageDataUrl.indexOf(',');
  const header = imageDataUrl.slice(0, comma);
  base64Data   = imageDataUrl.slice(comma + 1);
  mediaType    = header.match(/data:([^;]+)/)?.[1] || 'image/jpeg';
}

return [{ json: { base64Data, mediaType, filename, matchCount, matchThreshold } }];

