const visionResponse = $input.first();
const description = visionResponse.json.content?.[0]?.text || '';

const prepareNode   = $('Prepare image').first();
const matchCount    = prepareNode.json.matchCount    || 6;
const matchThreshold = prepareNode.json.matchThreshold || 0.30;

return [{ json: { description, matchCount, matchThreshold } }];

const searchResults = $input.first();
const raw = searchResults.json;
const matches = Array.isArray(raw) ? raw : [];

const description = $('Extract description').first().json.description;

const formattedMatches = matches.map(ring => ({
  ring_id:   ring.ring_id   || ring.id,
  name:      ring.name,
  thumbnail: ring.thumbnail_url || ring.image_url || null,
  url:       ring.product_url   || ring.url       || null,
  metal:     ring.metal  || null,
  style:     ring.style  || null,
  price:     ring.price  || null,
  similarity: ring.similarity
}));

return [{ json: { description, matches: formattedMatches } }];
